--预处理数据
function ModelFormation:OnModelInit()
    self:ParseConfig()
    self:InitData()
    self:ModelNetMsgRecv(LProtoIds.SetFormationResp, function(...)
        --print("--------- zhenxing shezhi fanhui")
        self:OnSetFormationResp(...)
        -- gLFightManager:ReqABattle()
    end)

    self:ModelNetMsgRecv(LProtoIds.GetFormationListResp, function(...)
        self:OnGetFormationListResp(...)
    end)

    self:ModelNetMsgRecv(LProtoIds.GetFormationResp, function(...)
        self:OnGetFormationResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.HeroRemoveFormationResp, function(...)
        self:OnHeroRemoveFormationResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.FormationExchangeResp, function(...)
        self:OnFormationExchangeResp(...)
    end)

    self:ModelNetMsgRecv(LProtoIds.SetFormationMultipleResp, function(...)
        self:OnSetFormationMultipleResp(...)
    end)

    local pbId = LProtoHelper.GetProtoId("SetFormationResp")
    self:ModelEventRecv(EventNames.NET_ERROR_CODE, function(msgId, error, args, errorStr)
        if pbId == msgId then
            self._setFormationRespIndex = self._setFormationRespIndex + 1
        end
    end)
    self._setFormationRespIndex = 0
    self._setFormationReqIndex = 0


end

