function ModelFormation:IncreaseFormationReqIndex()
    local index = self._setFormationReqIndex + 1
    if index > 2147483647 then
        index = 0
    end
    self._setFormationReqIndex = index
    return index
end

function ModelFormation:OnSetFormationResp(pb, ret)
    local teamIndexSet = pb.teamIndexSet
    local first = teamIndexSet[1]
    if not first then
        return
    end

    local formationType = first.formationType
    local teamIndex = first.teamIndex[1]

    local oldData = self:GetFormation(formationType,teamIndex)

    local formationdataList = self._tempFormations[formationType]
    if formationdataList then
        local formationdata = formationdataList[teamIndex]
        if formationdata then
            local dictType = {}
            for k, v in ipairs(teamIndexSet) do
                local type = v.formationType
                if type == LCombatTypeConst.COMBAT_ACTIVITY_DREAMTRIP then
                    type = LCombatTypeConst.COMBAT_MAIN
                end
                dictType[type] = true
                for k1, v1 in ipairs(v.teamIndex) do
                    local index = v1
                    self:SaveFormation(formationdata, type, index)
                end
            end
            FireEvent(EventNames.ON_SET_FORMATION_RESP, dictType)
        end

    end
    --=1 表示仅仅是阵型设置操作
    local formationSetType = pb.formationSetType or 0
    if formationSetType == 1 then
        if formationType == 1 then
            FireEvent(EventNames.On_Hero_Change)
        end
        if formationType == LCombatTypeConst.COMBAT_SHOW_BATTLE and not oldData then
        else
            GF.ShowMessage(ccClientText(10346))
        end
        return
    end

    gModelBattle:OnSetFormationRet(pb)


end

function ModelFormation:OnSetFormationMultipleResp(pb)
    local teamIndexSet = pb.teamIndexSet

    for k, v in ipairs(teamIndexSet) do
        local type = v.formationType
        for k1, v1 in ipairs(v.teamIndex) do
            local index = v1
            local dataList = self._tempFormations[type]
            local data = dataList and dataList[index]
            if data then
                self:SaveFormation(data, type, index)
            end
        end
    end

    if pb.formationSetType == 0 then
        gModelBattle:OnSetFormationRet(pb)
    else
        GF.ShowMessage(ccClientText(10346))
    end
end

