function ModelFormation:OnHeroRemoveFormationReq(heroId, page, sortLayer, isClose, noOpenSelWndList)

    self._removeFromPage = page or 1
    self._removeSortLayer = sortLayer or LGameUI.UI_SORTLAYER_UIBOTTOM
    self._removeIsClose = isClose
    self._noOpenSelWndList = noOpenSelWndList or {}

    local removeFunc = function()
        local pb = LProtoHelper.CreateProto(LProtoIds.HeroRemoveFormationReq)
        pb.heroId = heroId
        SendMessage(pb, LProtoIds.HeroRemoveFormationReq)

        self._removeTarget = heroId
    end

    local serverData = gModelHero:GetHeroServerDataById(heroId)
    if serverData then
        local combatType = serverData.combatType
        local firstData = combatType[1]
        local isMore = #combatType > 1
        if firstData then
            if firstData == LCombatTypeConst.COMBAT_DREAMTRIP then
                gModelGeneral:ShowUIOrdinTipLazy(230008, function()
                    --gModelFunctionOpen:Jump(17100400)
                end)
            else
                local name = gModelBattle:GetCombatTypeName(firstData)
                if isMore then
                    name = name .. ccClientText(16606)
                end
                gModelGeneral:ShowUIOrdinTipLazy(50901, removeFunc, { para = { name } })
            end
        end
    end
end

