function ModelFormation:OnMonsterPowerReq(monsterIds, formationA, combatType, reqIndex)
    local pb = LProtoHelper.CreateProto(LProtoIds.MonsterPowerReq)

    for i, v in ipairs(monsterIds) do
        local _data = pb.data
        local monsterForMationData = _data:add()
        monsterForMationData.monsterId = v

        if formationA then
            local formation = formationA[i]
            if formation and combatType then
                local data = monsterForMationData.data
                data.formationType = combatType or LCombatTypeConst.COMBAT_MAIN
                data.teamIndex = 0
                data.formationRefId = formation.formationRefId or 1
                -- data.artifactId = formation.artifactId or 0【G公共支持】删除神器功能相关数据

                local pbGrids = data.grids
                for k, v in ipairs(formation.grids or {}) do
                    local girld = pbGrids:add()
                    girld.id = tostring(v.id)
                    girld.grid = v.grid
                end

                -- local _treasureSkilIds = data.treasureSkilIds
                -- for i,v in ipairs(formation.treasureSkilIds or {}) do
                -- 	table.insert(_treasureSkilIds,v)
                -- end
            end
        end
    end
    if reqIndex then
        pb.reqIndex = reqIndex
    end
    SendMessage(pb, LProtoIds.MonsterPowerReq)
end

function ModelFormation:OnSetFormationList(formationData)
    local formationType = formationData.formationType or LCombatTypeConst.COMBAT_MAIN
    local teamIndex = formationData.teamIndex or 0
    local combatTypeList = formationData.combatTypeList or {}

    local reqIndex = formationData.reqIndex or 0
    local formationSetType = formationData.formationSetType

    local pb = LProtoHelper.CreateProto(LProtoIds.SetFormationReq)
    pb.formationSetType = formationSetType

    local data = pb.data

    self:FillIntoFormationData(data, formationData)

    local formationData = self:GemFormationData(pb.data)
    self:SaveTempFormation(formationData, formationType, teamIndex)

    local teamIndexSet = pb.teamIndexSet
    local set = teamIndexSet:add()
    set.formationType = formationType
    set.teamIndex:append(teamIndex)

    for k, v in pairs(combatTypeList) do
        local set = teamIndexSet:add()
        set.formationType = k
        for k1, v1 in pairs(v) do
            set.teamIndex:append(v1)
        end
    end
    pb.reqIndex = reqIndex

    SendMessage(pb, LProtoIds.SetFormationReq)
end

function ModelFormation:OnFormationExchangeReq(formationType, formationIndex, targetType, targetIndex)
    local pb = LProtoHelper.CreateProto(LProtoIds.FormationExchangeReq)
    pb.formationType = formationType
    pb.formationIndex = formationIndex
    pb.targetType = targetType
    pb.targetIndex = targetIndex
    SendMessage(pb, LProtoIds.FormationExchangeReq)
end

function ModelFormation:SetFormationMultipleReq(formationList, setType, reqIndex)
    local pb = LProtoHelper.CreateProto(LProtoIds.SetFormationMultipleReq)
    pb.formationSetType = setType or 0
    pb.reqIndex = reqIndex

    for k, v in pairs(formationList) do
        local data = pb.data:add()

        local combatType = v.combatType
        local teamIndex = k
        local indexToGrid = self:GetFormationPosByRefId(v.arrayId)
        local grids = {}
        local isEmpty = true
        for k1, v1 in pairs(v.idToIndex) do
            isEmpty = false
            local grid = {
                id = tostring(k1),
                grid = indexToGrid[v1],
            }
            table.insert(grids, grid)
        end

        local tempData = {
            formationType = combatType,
            teamIndex = teamIndex,
            formationRefId = v.arrayId,
            -- artifactId = 0,【G公共支持】删除神器功能相关数据
            tactics = v.tactics,
            grids = grids,
            treasureSkilIds = v.treasureIdList,
            divineWeaponStarRefIds = v.divineWeaponStarIdList,
            -- treasurePassiveSkill = v.pasvList,
            -- 【C宠物系统】删掉宠物系统相关
            -- petFights = v.petFights,
            -- petHelps = v.petHelps,
        }

        self:FillIntoFormationData(data, tempData)

        if not isEmpty then
            local formationData = self:GemFormationData(data)
            self:SaveTempFormation(formationData, combatType, teamIndex)
        end

    end

    SendMessage(pb, LProtoIds.SetFormationMultipleReq)

end

function ModelFormation:OnSetFormationMultipleReqEx(formationList, setType, reqIndex)
    local pb = LProtoHelper.CreateProto(LProtoIds.SetFormationMultipleReq)
    pb.formationSetType = setType or 0
    pb.reqIndex = reqIndex

    for k, v in pairs(formationList) do

        local data = pb.data:add()

        self:FillIntoFormationData(data, v)
        local combatType = v.formationType
        local teamIndex = v.teamIndex

        local formationData = self:GemFormationData(data)
        self:SaveTempFormation(formationData, combatType, teamIndex)

    end

    SendMessage(pb, LProtoIds.SetFormationMultipleReq)
end

