function ModelFormation:OnHeroRemoveFormationResp(pb)
    local isSuc = pb.isSucc == 1
    if isSuc then
        GF.ShowMessage(ccClientText(10150))
        return
    end

    local record = {}
    for k, v in ipairs(pb.refIds) do
        record[v] = true
    end

    local combatType = pb.refIds[1]

    local name = gModelBattle:GetCombatTypeName(combatType)

    if #pb.refIds > 1 then
        name = name .. ccClientText(16606)
    end

    local para = {
        refId = 10006,
        para = { name },
        func = function()
            local returnFunc = function()

                gModelGeneral:RecoverGameState()
            end

            gModelGeneral:RecordGameState(self._noOpenSelWndList)

            local heroId = self._removeTarget
            self._removeTarget = nil
            self:OpenSetFormationWnd({ typeRecord = record, returnFunc = returnFunc, removeTarget = heroId })
        end
    }

    gModelGeneral:OpenUIOrdinTips(para)
end

function ModelFormation:OnGetFormationListResp(pb, ret)
    local dataList = pb.dataList
    local formationType, teamIndex

    for k, v in ipairs(dataList) do
        formationType = v.formationType
        teamIndex = v.teamIndex

        local data = self:GemFormationData(v)
        self:SaveFormation(data, formationType, teamIndex)
        gModelPower:SaveFormationPower(formationType, v.power)
    end

    FireEvent(EventNames.ON_GET_FORMATION_LIST_RET, formationType)
end

function ModelFormation:OnGetFormationResp(pb, ret)
    local type = pb.type
    local teamIndex = pb.teamIndex
    if pb.data.formationType > 0 then
        local formationData = self:GemFormationData(pb.data)

        self:SaveFormation(formationData, formationData.formationType, formationData.teamIndex)
    end

    gModelPower:SaveFormationPower(pb.type, pb.power)

    FireEvent(EventNames.ON_GET_FORMATION_RET, type, teamIndex)


end

function ModelFormation:OnlySetFormationReq(data)

    local formationData = {
        formationSetType = 1,
        formationType = data.combatType,
        teamIndex = data.teamIndex,
        treasureSkilIds = data.treasureSkilIds,
        grids = data.grids,
        reqIndex = 0,
        formationRefId = data.formationRefId,
        tactics = data.tactics,
        divineWeaponStarRefIds= data.divineWeaponStarRefIds,
        -- petFights = data.petFights,
        -- petHelps = data.petHelps,
    }

    self:OnSetFormationList(formationData)
end

function ModelFormation:OnFormationExchangeResp(pb, ret)

    local data = self:GemFormationData(pb.data)
    local combatType = data.formationType
    local teamIndex = data.teamIndex
    self:SaveFormation(data, combatType, teamIndex)

    local targetData = self:GemFormationData(pb.targetData)
    combatType = targetData.formationType
    teamIndex = targetData.teamIndex
    self:SaveFormation(targetData, combatType, teamIndex)
end

