function ModelFormation:GetFormationCfgList(flist)
    local list = {}
    for k, v in pairs(GameTable.BattleFormationRef) do
        if flist then
            if v.type == 1 and flist[v.refId] then
                table.insert(list, v)
            end
        else
            if v.type == 1 then
                table.insert(list, v)
            end
        end
    end

    table.sort(list, function(a, b)
        return a.refId < b.refId
    end)
    return list
end

