function ModelFormation:GetCombatCampEffBySelType(selType)
    local ref = {}
    local index = 1
    for k, v in pairs(GameTable.BattleCampEffRef) do
        local rType = v.type
        if rType == selType then
            ref[index] = v
            index = index + 1
        end
    end
    return ref
end

function ModelFormation:GetGradeNum(selType, haveNum)
    local have = 0
    local ref = self:GetCombatCampEffBySelType(selType)
    if ref then
        for k, v in pairs(ref) do
            local condition = v.condition
            local conditionList = string.split(condition, ",")
            for i = 1, #conditionList do
                local temp = string.split(conditionList[i], "=")
                local needNum = tonumber(temp[2])
                if selType ~= 4 and selType ~= 5 then
                    if haveNum == needNum then
                        have = needNum - 1
                        return have
                    end
                else
                    return haveNum
                end
            end
        end
    end
    return have
end

function ModelFormation:GetFormationList(formationType)
    if not self._formations then
        return nil
    end
    local list = self._formations[formationType]
    if not list then
        return nil
    end
    return list
end

function ModelFormation:GetFormation(formationType, teamIndex)
    local teamIndex = teamIndex or 0
    if not self._formations then
        return nil
    end
    local list = self._formations[formationType]
    if not list then
        return nil
    end
    local formationdata = list[teamIndex]
    return formationdata
end

function ModelFormation:CheckFormationDraconic(upRefId)
    for _, list in pairs(self._formations) do
        for _, formation in pairs(list) do
            for k, refId in pairs(formation.treasureSkilIds or {}) do
                formation.treasureSkilIds[k] = gModelDraconic:CompareSpeech(refId, upRefId)
            end
        end
    end
end

function ModelFormation:GetFormationPower(formationType)
    local formationdata = self:GetFormation(formationType)
    if formationdata then
        return formationdata.power
    end
    return nil
end

function ModelFormation:CalcFormationPowerByFormationType(formationType)
    local formationdata = self:GetFormation(formationType)
    if formationdata then
        local grids = formationdata.grids
        if grids and #grids > 0 then
            local power = 0
            for i, v in ipairs(grids) do
                local heroStruct = gModelHero:GetHeroById(v.id)
                if heroStruct then
                    power = power + heroStruct:GetPower()
                end
            end
            if power > 0 then
                return power
            end
        end
    end
    return nil
end

function ModelFormation:GetFormationMatrixRefId(formationType)
    local formation = self:GetFormation(formationType)
    if formation then
        local refId = formation.formationRefId
        refId = refId == 0 and 1 or refId
        return refId
    end
    return nil
end

function ModelFormation:GetOnHookHeroList()
    local defendFormation = self:GetFormation(LCombatTypeConst.COMBAT_ON_HOOK_DEFEND)
    local heroList = {}
    if defendFormation and defendFormation.grids then
        for k, v in ipairs(defendFormation.grids) do
            table.insert(heroList, v.id)
        end
    end
    return heroList
end

function ModelFormation:GetPrefabName()
    local heroList = self:GetOnHookHeroList()
    if (not heroList) then
        return nil
    end
    for i, v in pairs(heroList) do
        return gModelHero:GetHeroPrefabNameById(v)
    end
end

function ModelFormation:GetFormationPosByRefId(refId)
    local posInfo = self._formationT[refId]
    if not posInfo then
        printErrorN(string.format("wrong formation ref Id %s", refId))
        return {}
    end
    return posInfo.indexToGrid
end

function ModelFormation:GetHeroFormationData(formationType, teamIndex)
    local formation = self:GetFormation(formationType, teamIndex)
    return self:GetMapFormationData(formation)
end

function ModelFormation:GetMapFormationData(formation)
    local t = {}

    if not formation then
        return t
    end

    if not formation.grids then
        return t
    end

    local formationType = formation.formationType
    local matrixRefId = formation.formationRefId

    for k, v in ipairs(formation.grids) do
        local heroId = v.id
        local isExist = false
        if formationType == LCombatTypeConst.COMBAT_WONDERLAND then
            local serData = gModelWonderland:GetHeroData(heroId)
            isExist = serData ~= nil and serData.curHp > 0
            -- elseif formationType == LCombatTypeConst.COMBAT_DESIRETRAIL then
            -- 	local serData = gModelDesireTrail:GetHeroData(heroId)
            -- 	isExist = serData and serData.curHp > 0
            --elseif gModelBattle:IsTimeCorridorCombat(formationType) then
            --	local serData = gModelTimeCorridor:GetHeroData(heroId)
            --	isExist = serData~=nil and serData.curHp>0
        elseif gModelBattle:IsEndlessCombat(formationType) then
            local serData = gModelEndles:GetEndlessHeroData(formationType, heroId)
            isExist = serData ~= nil
        else
            local serData = gModelHero:GetHeroById(heroId)
            isExist = serData ~= nil
        end

        if isExist then
            local data = {
                heroId = v.id,
                posIndex = self:GetIndexByPos(matrixRefId, v.grid),
                pos = v.grid,
            }
            t[v.id] = data
        end
    end

    return t
end

function ModelFormation:GetHeroFormationByHeroId(formationType, heroId)
    local formation = self:GetFormation(formationType)
    if formation then
        for k, v in ipairs(formation.grids) do
            local id = v.id
            if id == heroId then
                return true
            end
        end
    end
    return false
end

function ModelFormation:GetIndexByPos(matrixRefId, pos)
    local matrix = self._formationT[matrixRefId]
    if not matrix then
        LogError(string.format("no matrix refId %s", matrixRefId))
        return 1
    end
    local posIndex = matrix.gridToIndex[pos] or 1
    if not posIndex then
        LogError(string.format("formation wrong refId %s pos %s", matrixRefId, pos))
    end
    return posIndex
end

function ModelFormation:GetFormationMatrix(refId)
    local matrix = self._formationT[refId]
    if not matrix then
        LogError(string.format("no matrix refId %s", refId))
    end
    return matrix
end

function ModelFormation:GetOnHookHeroName()
    local heroList = self:GetOnHookHeroList()
    if (not heroList) then
        return nil
    end

    local heroId = heroList[1]
    if not heroId then
        return nil
    end
    local name = gModelHero:GetHeroNameById(heroId)
    return name
end

function ModelFormation:GetOnFormationHeros(combatType, teamIndex)
    local formation = self:GetFormation(combatType, teamIndex)
    if not formation or not formation.grids then
        return {}
    end
    local record = {}
    for k, v in ipairs(formation.grids) do
        local heroId = v.id
        record[heroId] = true
    end

    return record
end

function ModelFormation:GetFormationHerosNum(combatType)
    --获取阵容人数
    local heroRecord = self:GetOnFormationHeros(combatType)
    local cnt = 0
    for k, v in pairs(heroRecord) do
        cnt = cnt + 1
    end
    return cnt
end

function ModelFormation:GetFormationHeroCnt(combatType, teamIndex)
    local formation = self:GetFormation(combatType, teamIndex)
    if not formation or not formation.grids then
        return 0
    end

    return #formation.grids
end

--获取是否布阵为空
function ModelFormation:IsFormationEmpty(combatType)
    local list = self:GetFormationList(combatType)
    if not list then
        return true
    end
    for k, v in pairs(list) do
        if v.grids and #v.grids > 0 then
            return false
        end
    end
    return true
end
