function ModelFormation:IsAnyValidHeroInFormation(combatType)
    local formation = self:GetFormation(combatType)
    if not formation or not formation.grids then
        return false
    end
    local data = formation
    for k, v in ipairs(data.grids) do
        local heroId = v.id
        if heroId then
            local heroData = gModelHero:GetHeroById(heroId)
            if heroData then
                return true
            end
        end
    end

    return false
end

