function ModelFormation:GetMultiOneKey(formationType, raceFilter, idRecord, total, forbiddenList)
    --local total = total or 5
    --
    local total = total or 6
    local heroList = gModelHero:GetHeroList()
    local list = {}
    local canUpTry = gModelBattle:CheckCombatPlayCampShowHeroFree(formationType)
    for k, v in pairs(heroList) do
        local isTryHero = v:IsTryHero()
        if not isTryHero or canUpTry then
            local id = v:GetId()
            local refId = v:GetRefId()
            local isForbidden = forbiddenList and forbiddenList[refId]
            if not idRecord[id] and not self:CheckLinkForbid(formationType, id, nil, idRecord) and not isForbidden then
                local ref = gModelHero:GetHeroRef(refId)
                if ref then
                    local race = ref.raceType
                    if not raceFilter or raceFilter[race] then
                        local data = {
                            id = id,
                            refId = refId,
                            power = v:GetPower(),
                            race = race,
                        }
                        table.insert(list, data)
                    end
                end
            end
        end
    end
    table.sort(list, function(hero1, hero2)
        local power1, power2 = hero1.power, hero2.power
        if power1 ~= power2 then
            return power1 > power2
        end
        local isAPrio = hero1.race == ModelSpiritHero.SPIRITHERO_RACE and 1 or 2
        local isBPrio = hero2.race == ModelSpiritHero.SPIRITHERO_RACE and 1 or 2
        if isAPrio ~= isBPrio then
            return isAPrio > isBPrio
        end
        local id1, id2 = hero1.id, hero2.id
        return id1 > id2
    end)

    local heroDataList = {}
    local refIdRecord = {}
    local cnt = 0

    local curRecord = {}
    for k, v in ipairs(list) do
        local refId = v.refId
        if refId and not refIdRecord[refId] and not self:CheckLinkForbid(formationType, v.id, curRecord, nil) then
            local isMappingHero = gModelResonance:CheckListHasMappingHero(v.id, curRecord, idRecord)
            if not isMappingHero then
                refIdRecord[refId] = true
                cnt = cnt + 1
                local career = gModelHero:GetHeroCareerType(refId)
                v.career = career
                table.insert(heroDataList, v)
                curRecord[v.id] = true
            end
        end
        if cnt >= total then
            break
        end
    end
    return self:OneKeyInternal(heroDataList, formationType)
end

function ModelFormation:OneKeyInternal(heroDataList, formationType)

    table.sort(heroDataList, function(a, b)
        local aPrio = self._upPrioty[a.career]
        local bPrio = self._upPrioty[b.career]
        if aPrio ~= bPrio then
            return aPrio < bPrio
        end
        return a.power > b.power
    end)

    local matrix = self:GetFormationPosByRefId(formationType)
    local posRecord = {}

    local heroUpRecord = {}
    for k, v in pairs(matrix) do
        table.insert(posRecord, false)
    end

    local minIndex = 1
    local maxIndex = #posRecord
    for k, v in ipairs(heroDataList) do
        if minIndex > maxIndex then
            break
        end
        local aCareer = v.career
        if aCareer == ModelHero.CAREER_GUARD then
            heroUpRecord[minIndex] = v.id
            minIndex = minIndex + 1
        else
            heroUpRecord[maxIndex] = v.id
            maxIndex = maxIndex - 1
        end
    end

    return heroUpRecord
end

