function ModelFormation:GetCombatTypeList(record, include, exclude)

    local record = record or {}
    local dataList = {}
    for k, v in pairs(GameTable.BattleGameRef) do
        local isShow = v.campOpen == 1
        if isShow then
            local campSort = v.campSort
            if campSort ~= 0 then
                local id = v.campOpenLv
                local isOpen = gModelFunctionOpen:CheckIsOpened(id, false)
                if isOpen then
                    table.insert(dataList, v)
                end
            end
        end
    end

    if include then
        local filterList = {}
        for k, v in ipairs(dataList) do
            local request = include[v.refId]
            if request then
                table.insert(filterList, v)
            end
        end
        dataList = filterList
    end

    if exclude then
        local filterList = {}
        for k, v in ipairs(dataList) do
            local request = exclude[v.refId]
            if not request then
                table.insert(filterList, v)
            end
        end
        dataList = filterList
    end

    if #dataList > 1 then
        table.sort(dataList, function(a, b)
            local isOneOn = record[a.refId] and 1 or 2
            local isTwoOn = record[b.refId] and 1 or 2
            if isOneOn ~= isTwoOn then
                return isOneOn < isTwoOn
            end

            return a.campSort < b.campSort
        end)
    end
    return dataList
end

function ModelFormation:GetCombatGameRef(refId)
    return GameTable.BattleGameRef[refId]
end
--種族激活數量
function ModelFormation:GetRaceList(refIdList)
    local raceTypeList = {}
    local yaoshi = {}
    local yaoshiNum = 0
    local tempMaxRace  = 0
    for k, v in ipairs(refIdList or {}) do
        local isHero = not v.isMon
        local id = v.id
        local raceType = nil
        local heroRef = gModelHero:GetHeroRef(id)
        local isYaoshi = false
        if isHero then
            -- 英雄种族
            if heroRef then
                raceType = heroRef.raceType
                isYaoshi = heroRef.superHero and heroRef.superHero > 0
                if isYaoshi then
                    table.insert(yaoshi, raceType)
                end
                if raceType > tempMaxRace then
                    tempMaxRace = raceType
                end
            end
        else
            -- 怪物种族
            local ref = gModelHero:GetMonsterAttrByRefId(id)
            if ref then
                raceType = ref.raceType
            end
        end
        if raceType and not isYaoshi then
            local raceCnt = raceTypeList[raceType]
            if not raceCnt then
                raceCnt = 0
            end
            raceCnt = raceCnt + 1
            raceTypeList[raceType] = raceCnt
        end
    end
    yaoshiNum = #yaoshi
    if yaoshiNum > 0 then
        --耀世加成計算
        local keysize = table.keysize(raceTypeList)
        for _, yaoshiRace in ipairs(yaoshi) do
            local maxNum = 0
            local maxRace = nil
            if keysize > 0 then
                for key, value in pairs(raceTypeList) do
                    if value > maxNum or (value == maxNum and key > maxRace) then
                        --數量最多的種族、相同數種族id最大的種族
                        maxNum = value
                        maxRace = key
                    end
                end
                if raceTypeList[yaoshiRace] and raceTypeList[yaoshiRace] == maxNum then
                    --（数量相同）
                    -- if (yaoshiRace == 4 or yaoshiRace == 5) then--and raceTypeList[yaoshiRace]
                    --     --上阵种族里是否有光暗，耀辉是光暗 且 存在耀辉原種族
                    --     maxRace = yaoshiRace
                    -- end
                    -- if yaoshiRace <= 3 then--and raceTypeList[yaoshiRace]
                    --     --上阵种族里没光暗，耀辉是三系 且 存在耀辉原種族
                    --     maxRace = yaoshiRace
                    -- end
                    maxRace = yaoshiRace
                end
                local count = raceTypeList[maxRace] or 0
                raceTypeList[maxRace] = count + 1
            else
                --數量0的情況
                if yaoshiRace == 4 or yaoshiRace == 5 then
                    local count = raceTypeList[yaoshiRace] or 0
                    raceTypeList[yaoshiRace] = count + 1
                else
                    --local heroRaceRef = gModelHero:GetHeroRaceRef()
                    maxRace = tempMaxRace --heroRaceRef[#heroRaceRef].refId
                    local count = raceTypeList[maxRace] or 0
                    raceTypeList[maxRace] = count + 1
                end
                keysize = 1
            end
        end
    end

    return raceTypeList, yaoshiNum
end

function ModelFormation:GetActivityData(raceTypeList)
    local raceActNumList = {}                                                    -- 种族激活数量
    local sortRaceActList = {}
    local effRefIdList = {}
    for k, v in pairs(raceTypeList) do
        local actLevel, refId, priority, raceType, effRefId = self:GetRaceActivityLevel(k, v)
        if actLevel and actLevel > 0 then
            local actInfo = {
                actLevel = actLevel,
                refId = refId,
                priority = priority,
                raceType = raceType,
                effRefId = effRefId,
            }
            raceActNumList[k] = actInfo
            effRefIdList[effRefId] = actInfo
            table.insert(sortRaceActList, actInfo)
        end
    end
    local isStandard, standardInfo = self:IsType6RaceActivity(raceTypeList)
    if isStandard then
        --[[		-- 融合之力
                local raceType6 = ModelFormation.TYPE_BUFF_FUSION_RACE
                local type6Info = self._rejectList[ModelFormation.TYPE_BUFF_FUSION]
                local type6RefData = self._formationEffT[raceType6][1]
                local actInfo = {
                    actLevel = type6RefData.level,
                    refId = type6RefData.refId,
                    priority = type6Info.priority,
                    raceType = type6RefData.hero,
                }
                raceActNumList[raceType6] = actInfo
                sortRaceActList = {}
                table.insert(sortRaceActList,actInfo)]]

        raceActNumList[ModelFormation.TYPE_BUFF_FUSION_RACE] = {
            actLevel = standardInfo.level,
            refId = standardInfo.refId,
            priority = standardInfo.priority,
            raceType = standardInfo.raceType,
            reject = standardInfo.reject,
            effRefId = standardInfo.effRefId,
        }
        effRefIdList[standardInfo.effRefId] = standardInfo
        sortRaceActList = {}
        table.insert(sortRaceActList, standardInfo)
    end
    table.sort(sortRaceActList, function(race1, race2)
        local priority1, priority2 = race1.priority, race2.priority
        if priority1 ~= priority2 then
            return priority1 > priority2
        else
            return race1.refId > race2.refId
        end
    end)
    return raceActNumList, sortRaceActList, isStandard, effRefIdList
end
--
function ModelFormation:GetActRefIdlist(raceTypeList)
    local raceActNumList, sortRaceActList, isStandard, effRefIdList = self:GetActivityData(raceTypeList)
    local actList = {}
    for i, v in ipairs(sortRaceActList) do
        local join = true
        local effRefId = v.effRefId
        local reject, priority = self:GetRejectInfo(effRefId)
        for idx, raceReject in ipairs(reject) do
            if effRefIdList[raceReject] then
                -- 有该类型的数据
                local tempReject, tempPrioity = self:GetRejectInfo(raceReject)
                for tempIdx, tempRaceReject in ipairs(tempReject) do
                    if tempRaceReject == effRefId then
                        join = priority > tempPrioity
                    end
                end
            end
        end
        if join then
            table.insert(actList, v.raceType)
        end
    end
    return actList
end

function ModelFormation:GetBuffInfo(refIdList)
    local iconPath = nil -- "public_race_icon_buff_0"
    local effectName = nil
    local size = #refIdList
    local isActive = false
    if size > 0 then
        local raceTypeList = self:GetRaceList(refIdList)

        --[[		local type4Num = raceTypeList[4] or 0 		-- 光上阵数量
                local type5Num = raceTypeList[5] or 0		-- 暗上阵数量
                local actLevel4 = self:GetRaceActivityLevel(4,type4Num) or 0 		-- 光激活等级
                local actLevel5 = self:GetRaceActivityLevel(5,type5Num)	or 0		-- 暗激活等级]]

        local actList = self:GetActRefIdlist(raceTypeList)

        --local icon =nil
        --local eff = nil

        local combatCampRef = self:GetCombatCampRef()
        local len = #actList
        if len == 1 then
            isActive = true
            local refId
            local raceTypeRefId = actList[len]
            for k, v in pairs(combatCampRef) do
                if v.hero == raceTypeRefId then
                    refId = v.refId
                end
            end
            refId = refId or 0

            local ref = self:GetCombatCampById(refId)
            if ref then
                iconPath = ref.icon
                effectName = ref.campIconEff
            end
        elseif len > 1 then
            isActive = true
            len = math.min(3, len)
            local iconStr = GameTable.BattleConfigRef["campIcon"]
            local iconList = string.split(iconStr, ",")
            iconPath = iconList[len - 1]

            local effStr = GameTable.BattleConfigRef["campIconEff"]
            local effList = string.split(effStr, ",")
            effectName = effList[len - 1]
        end
        --iconPath = icon
        --effectName = eff
    end
    return iconPath, effectName, isActive
end

function ModelFormation:GetRejectInfo(raceType)
    local reject, priority = {}, 0
    local rejectInfo = self._rejectList[raceType]
    if rejectInfo then
        reject, priority = rejectInfo.reject, rejectInfo.priority
    end
    return reject, priority
end

function ModelFormation:GetRaceActivityLevel(race, num)
    local formationEffT = self._formationEffT
    local raceTypeList = formationEffT[race]
    local haveNum, raceRefId, priority, raceType, effRefId
    for i, v in ipairs(raceTypeList) do
        if haveNum then
            break
        end
        local condition = string.split(v.condition, "=")
        if num == tonumber(condition[2]) then
            haveNum = v.level
            raceRefId = v.refId
            priority = v.priority
            raceType = tonumber(condition[1])
            effRefId = v.type
        end
    end
    return haveNum, raceRefId, priority, raceType, effRefId
end

function ModelFormation:IsType6RaceActivity(list)
    local formationInfo = self._formationEffT[ModelFormation.TYPE_BUFF_FUSION_RACE]
    if formationInfo then
        --[[		local conditionList = string.split(formationInfo[1].condition,"|")
                for i,v in ipairs(conditionList) do
                    local standardList = {}
                    local condition = string.split(v,",")
                    for idx,val in ipairs(condition) do
                        val = string.split(val,"=")
                        local raceType,raceNum = tonumber(val[1]),tonumber(val[2])
                        standardList[raceType] = false
                        local listData = list[raceType] or 0
                        standardList[raceType] = listData >= raceNum
                    end
                    local status = true
                    for tRaceType,tStatus in pairs(standardList) do
                        if not tStatus then
                            status = false
                            break
                        end
                    end
                    if status then
                        return true
                    end
                end]]
        for i, v in ipairs(formationInfo) do
            local standardList = {}
            local condition = string.split(v.condition, ",")
            for idx, val in ipairs(condition) do
                val = string.split(val, "=")
                local raceType, raceNum = tonumber(val[1]), tonumber(val[2])
                standardList[raceType] = false
                local listData = list[raceType] or 0
                standardList[raceType] = listData >= raceNum
            end
            local status = true
            for tRaceType, tStatus in pairs(standardList) do
                if not tStatus then
                    status = false
                    break
                end
            end
            if status then
                local reject, priority = self:GetRejectInfo(v.type)
                return true, {
                    refId = v.refId,
                    priority = v.priority,
                    level = v.level,
                    raceType = v.hero,
                    effRefId = v.type,
                    reject = reject,
                }
            end
        end
    end
    return false
end

