function ModelFormation:OpenSetFormationWnd(para)
    if not para then
        para = {}
        para.setTargetType = LCombatTypeConst.COMBAT_MAIN
    else
        local setTargetType = para.setTargetType
        if not setTargetType then
            local dataList = self:GetCombatTypeList(para.typeRecord)
            if dataList and #dataList > 0 then
                setTargetType = dataList[1].refId
            else
                setTargetType = LCombatTypeConst.COMBAT_MAIN
            end
        end
    end

    para.wndType = 2
    GF.ChangeMap("LBattleMap", false, { isOnlySet = true, para = para })
end

function ModelFormation:OpenMultiOnlySet(para)
    para.wndType = 3
    GF.ChangeMap("LBattleMap", false, { isOnlySet = true, para = para })
end

function ModelFormation:OpenPetDreamLandOnlySet(para)
    para = para or {}
    para.wndType = 2
    GF.ChangeMap("LBattleMap", false, { isOnlySet = true, para = para })
end

