--配置预处理


function ModelFormation:ParseConfig()
    self._formationT = {}
    for k, v in pairs(GameTable.BattleFormationRef) do
        local formation = self:ParseFormation(v.positionValue)
        self._formationT[k] = formation
    end

    self._rejectList = {}
    local formationEffT = {}
    self._formationEffT = formationEffT
    for k, v in pairs(GameTable.BattleCampEffRef) do
        local cType = v.type
        local rejectInfo = self._rejectList[cType]
        if not rejectInfo then
            rejectInfo = {}
            rejectInfo.reject = {}
            rejectInfo.priority = v.priority
            self._rejectList[cType] = rejectInfo
            local reject = string.split(v.reject, "|")
            for idx, val in ipairs(reject) do
                table.insert(rejectInfo.reject, tonumber(val))
            end
        end

        local raceType = v.hero

        local typeList = formationEffT[raceType]
        if not typeList then
            typeList = {}
            formationEffT[raceType] = typeList
        end
        table.insert(typeList, v)
    end

    for k, v in pairs(formationEffT) do
        table.sort(v, function(t1, t2)
            return t1.level < t2.level
        end)
    end
end

function ModelFormation:SaveFormation(formationData, combatType, teamIndex)
    teamIndex = teamIndex or 0
    if not self._formations then
        self._formations = {}
    end
    if not self._formations[combatType] then
        self._formations[combatType] = {}
    end

    self._formations[combatType][teamIndex] = formationData
end

