---inex: 1-5 ,grid: 1-9
function ModelFormation:ParseFormation(str)
    local strs = string.split(str, ",")
    local matrix = {}
    matrix.indexToGrid = {}
    matrix.gridToIndex = {}
    for k, v in pairs(strs) do
        local tab = string.split(v, "=")
        if #tab ~= 2 then
            printInfoN("ModelFormation:ParseFormation, wrong cfg")
            break
        end
        local index = tonumber(tab[1])
        local pos = tonumber(tab[2])
        matrix.indexToGrid[index] = pos
        matrix.gridToIndex[pos] = index
    end
    return matrix
end

function ModelFormation:ModifyStoryFormation(grids, arrayId)
    local heroList = gModelHero:GetHeroList()

    local record = {}
    local gridRecord = {}
    for k, v in pairs(grids) do
        record[v.id] = v
        gridRecord[v.grid] = v
    end

    local leftHero = {}
    for k, v in pairs(heroList) do
        if not record[k] then
            table.insert(leftHero, k)
        end
    end

    if #leftHero == 0 then
        return
    end

    local matrix = self._formationT[arrayId]
    if not matrix then
        return
    end

    local gridToIndex = matrix.gridToIndex

    for k, v in pairs(gridToIndex) do
        if not gridRecord[k] then
            local id = table.remove(leftHero)
            if not id then
                return
            end
            local data = {
                id = id,
                grid = k
            }
            table.insert(grids, data)
        end
    end

end

function ModelFormation:CanChangeFormation(combatType)
    if combatType == LCombatTypeConst.COMBAT_ARENA_PEAK_ATTACK then
        return gModelArena:CanChangeFormation()
        -- 【G公共支持】删除跨服天梯和跨服周冠玩法
        -- elseif combatType == LCombatTypeConst.COMBAT_CROSS_SERVER_CHAMPION then
        -- 	return gModelCrossServer:CanChangeFormation()
    elseif combatType == LCombatTypeConst.COMBAT_GUILD_WAR then
        return gModelGuildMelee:GetIsChangeEmbattle()
    end
    return true
end

function ModelFormation:CheckFormationReady(combatType)
    if combatType == LCombatTypeConst.COMBAT_TYPE_75 then
        local teamCnt = gModelTower:GetHardTeamCnt()
        local formationList = self:GetFormationList(combatType) or {}

        for k = 0, teamCnt - 1 do
            if not formationList[k] then
                return false
            end
        end

        return true
    end
end

function ModelFormation:CheckTreasureNotUse(combatType, showTip)
