    local ref = self:GetCombatGameRef(combatType)
    if ref then
        local treasureUse = ref.treasureUse
        if treasureUse == 1 then
            if showTip then
                GF.ShowMessage(ccClientText(23763))
            end
            return true
        end
    end
    return false
end
function ModelFormation:CheckDivineNotUse(combatType, showTip)
