    end
    local ref = self:GetCombatGameRef(combatType)
    if ref then
        local weaponUse = ref.weaponUse
        if weaponUse == 1 then
            if showTip then
                GF.ShowMessage(ccClientText(23763))
            end
            return true
        end
    end
    return false
end

