---curRecord 当前队伍，extraRecord 其他编队
function ModelFormation:CheckLinkForbid(combatType, heroId, curRecord, extraRecord, showTip)
    local linkId = gModelSpiritHero:GetLinkHeroIdById(heroId)
    if string.isempty(linkId) then
        return false
    end

    local linkHero1 = 2;
    local linkHero2 = 2;
    local ref = self:GetCombatGameRef(combatType)
    if ref then
        linkHero1 = ref.linkHero1
        linkHero2 = ref.linkHero2
    end
    local exist = curRecord and curRecord[linkId]
    local existOther = extraRecord and extraRecord[linkId]
    if linkHero1 == 2 and (exist or existOther) then
        if showTip then
            GF.ShowMessage(ccClientText(31227))
        end
        return true
    end

    if linkHero2 == 2 and exist then
        if showTip then
            GF.ShowMessage(ccClientText(31228))
        end

        return true
    end

    return false
end

function ModelFormation:CheckCombatShowSpiritHero(combatType)
    if not combatType then
        return false
    end
    local status = LCombatTypeConst.COMBAT_SHOW_SPIRITHERO[combatType] or false
    if not status then
        local ref = self:GetCombatGameRef(combatType)
        if ref then
            status = ref.showSpirit or false
        end
    end
    return status
end

function ModelFormation:GemFormationData(data)
    local formationData = StructFormationData:New()
    formationData:CreateByPb(data)
    return formationData
end

-- 取水花与圣光作显示用
function ModelFormation:GetFormationBuffUiShow()
    local list1 = {}
    local list2 = {}
    local list3 = {}
    for k, v in pairs(GameTable.BattleCampEffRef) do
        if v.type == 1 then
            table.insert(list1, v)
        elseif v.type == 4 then
            table.insert(list2, v)
        elseif v.type == 7 then
            table.insert(list3, v)
        end
    end

    table.sort(list2, function(a, b)
        return a.refId < b.refId
    end)
    table.sort(list1, function(a, b)
        return a.refId < b.refId
    end)
    table.sort(list3, function(a, b)
        return a.refId < b.refId
    end)

    local heroMap1 = { 1, 2, 3 }
    local heroMap2 = { 4, 5 }
    local heroMap3 = { 6 }

    return list1, list2, heroMap1, heroMap2, list3, heroMap3
end


